import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useState, useEffect } from 'react';
import { userAPI, providerAPI } from '../utils/api';

export default function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [notifCount, setNotifCount] = useState(0);
  const [showMenu, setShowMenu] = useState(false);

  useEffect(() => {
    if (!user) return;
    const fetchNotifs = async () => {
      try {
        const api = user.role === 'provider' ? providerAPI : userAPI;
        const res = await api.getNotifications();
        const unread = res.data.filter(n => !n.is_read).length;
        setNotifCount(unread);
      } catch (e) {}
    };
    fetchNotifs();
    const interval = setInterval(fetchNotifs, 30000);
    return () => clearInterval(interval);
  }, [user]);

  const handleLogout = () => {
    logout();
    navigate('/');
    setShowMenu(false);
  };

  const isActive = (path) => location.pathname === path || location.pathname.startsWith(path + '/');

  return (
    <nav className="navbar">
      <Link to="/" className="nav-logo">
        🔧 Servi<span>fy</span>
      </Link>

      <div className="nav-links">
        <Link to="/search" className={`nav-link ${isActive('/search') ? 'active' : ''}`}>Browse Services</Link>
        {!user && (
          <>
            <Link to="/login" className={`nav-link ${isActive('/login') ? 'active' : ''}`}>Login</Link>
            <Link to="/register" className="btn btn-primary btn-sm">Get Started</Link>
          </>
        )}
      </div>

      {user && (
        <div className="nav-user" style={{ position: 'relative' }}>
          {user.city && (
            <div className="nav-city">
              📍 {user.city}
            </div>
          )}
          {notifCount > 0 && (
            <div style={{ position: 'relative', cursor: 'pointer' }} onClick={() => {
              if (user.role === 'provider') navigate('/provider');
              else navigate('/dashboard');
            }}>
              🔔
              <span style={{ position: 'absolute', top: -4, right: -4, background: 'var(--primary)', color: 'white', borderRadius: '50%', width: 16, height: 16, fontSize: 10, display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 700 }}>
                {notifCount > 9 ? '9+' : notifCount}
              </span>
            </div>
          )}
          <div
            className="nav-avatar"
            onClick={() => setShowMenu(!showMenu)}
            title={user.name}
          >
            {user.name?.[0]?.toUpperCase()}
          </div>
          {showMenu && (
            <div style={{
              position: 'absolute', top: '100%', right: 0, marginTop: 8,
              background: 'white', border: '1px solid var(--border)',
              borderRadius: 12, boxShadow: 'var(--shadow-lg)',
              minWidth: 200, zIndex: 200, padding: 8
            }}>
              <div style={{ padding: '8px 12px', borderBottom: '1px solid var(--border)', marginBottom: 4 }}>
                <div style={{ fontWeight: 600, fontSize: 14 }}>{user.name}</div>
                <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>{user.role} · {user.city}</div>
              </div>
              {user.role === 'user' && (
                <div className="sidebar-link" onClick={() => { navigate('/dashboard'); setShowMenu(false); }}>
                  📋 My Bookings
                </div>
              )}
              {user.role === 'provider' && (
                <div className="sidebar-link" onClick={() => { navigate('/provider'); setShowMenu(false); }}>
                  📊 Provider Dashboard
                </div>
              )}
              {user.role === 'admin' && (
                <div className="sidebar-link" onClick={() => { navigate('/admin'); setShowMenu(false); }}>
                  ⚙️ Admin Panel
                </div>
              )}
              <div style={{ borderTop: '1px solid var(--border)', marginTop: 4, paddingTop: 4 }}>
                <div className="sidebar-link" style={{ color: 'var(--danger)' }} onClick={handleLogout}>
                  🚪 Logout
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </nav>
  );
}
